172→#[async_trait]
173→impl CrmStore for SqliteCrmStore {
174→    // ── Contacts ──────────────────────────────────────────────────────────────
175→
176→    async fn list(&self) -> Result<Vec<Contact>> {
177→        let rows =
178→            sqlx::query_as::<_, ContactRow>(&format!("{SELECT_CONTACTS} ORDER BY updated_at DESC"))
179→                .fetch_all(&self.pool)
180→                .await?;
181→
182→        rows.into_iter().map(Contact::try_from).collect()
183→    }
184→
185→    async fn list_filtered(
186→        &self,
187→        stage: Option<ContactStage>,
188→        search: Option<&str>,
189→        offset: u64,
190→        limit: u64,
191→    ) -> Result<Vec<Contact>> {
192→        let mut sql = format!("{SELECT_CONTACTS} WHERE 1=1");
193→        if stage.is_some() {
194→            sql.push_str(" AND stage = ?");
195→        }
196→        if search.is_some() {
197→            sql.push_str(" AND (name LIKE ? OR email LIKE ? OR phone LIKE ?)");
198→        }
199→        sql.push_str(" ORDER BY updated_at DESC LIMIT ? OFFSET ?");
200→
201→        let mut q = sqlx::query_as::<_, ContactRow>(&sql);
202→        if let Some(s) = stage {
203→            q = q.bind(s.as_str());
204→        }
205→        if let Some(term) = search {
206→            let pattern = format!("%{term}%");
207→            q = q.bind(pattern.clone()).bind(pattern.clone()).bind(pattern);
208→        }
209→        q = q.bind(limit as i64).bind(offset as i64);
210→
211→        let rows = q.fetch_all(&self.pool).await?;
212→        rows.into_iter().map(Contact::try_from).collect()
213→    }
214→
215→    async fn get(&self, id: &str) -> Result<Option<Contact>> {
216→        let row = sqlx::query_as::<_, ContactRow>(&format!("{SELECT_CONTACTS} WHERE id = ?"))
217→            .bind(id)
218→            .fetch_optional(&self.pool)
219→            .await?;
220→
221→        row.map(Contact::try_from).transpose()
222→    }
223→
224→    async fn get_by_external(&self, source: &str, external_id: &str) -> Result<Option<Contact>> {
225→        let row = sqlx::query_as::<_, ContactRow>(&format!(
226→            "{SELECT_CONTACTS} WHERE source = ? AND external_id = ?"
227→        ))
228→        .bind(source)
229→        .bind(external_id)
230→        .fetch_optional(&self.pool)
231→        .await?;
232→
233→        row.map(Contact::try_from).transpose()
234→    }
235→
236→    async fn upsert(&self, contact: Contact) -> Result<()> {
237→        use secrecy::ExposeSecret;
238→        let metadata = serde_json::to_string(&contact.metadata)?;
239→        sqlx::query(
240→            r#"INSERT INTO crm_contacts
241→               (id, name, source, external_id, email, phone, stage, metadata, created_at, updated_at)
242→               VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
243→               ON CONFLICT(id) DO UPDATE SET
244→                 name        = excluded.name,
245→                 source      = excluded.source,
246→                 external_id = excluded.external_id,
247→                 email       = excluded.email,
248→                 phone       = excluded.phone,
249→                 stage       = excluded.stage,
250→                 metadata    = excluded.metadata,
251→                 updated_at  = excluded.updated_at"#,
252→        )
253→        .bind(&contact.id)
254→        .bind(&contact.name)
255→        .bind(&contact.source)
256→        .bind(&contact.external_id)
257→        .bind(contact.email.as_ref().map(|s| s.expose_secret().clone()))
258→        .bind(contact.phone.as_ref().map(|s| s.expose_secret().clone()))
259→        .bind(contact.stage.as_str())
260→        .bind(&metadata)
261→        .bind(contact.created_at as i64)
262→        .bind(contact.updated_at as i64)
263→        .execute(&self.pool)
264→        .await?;
265→        Ok(())
266→    }
267→
268→    async fn delete(&self, id: &str) -> Result<()> {
269→        sqlx::query("DELETE FROM crm_contacts WHERE id = ?")
270→            .bind(id)
271→            .execute(&self.pool)
272→            .await?;
273→        Ok(())
274→    }
