 31→    async fn list(&self) -> Result<Vec<Contact>> {
 32→        let contacts = self.contacts.read().unwrap_or_else(|e| e.into_inner());
 33→        let mut out: Vec<Contact> = contacts.values().cloned().collect();
 34→        out.sort_by_key(|c| std::cmp::Reverse(c.updated_at));
 35→        Ok(out)
 36→    }
 37→
 38→    async fn list_filtered(
 39→        &self,
 40→        stage: Option<ContactStage>,
 41→        search: Option<&str>,
 42→        offset: u64,
 43→        limit: u64,
 44→    ) -> Result<Vec<Contact>> {
 45→        use secrecy::ExposeSecret;
 46→
 47→        let contacts = self.contacts.read().unwrap_or_else(|e| e.into_inner());
 48→        let search_lower = search.map(str::to_lowercase);
 49→        let mut out: Vec<Contact> = contacts
 50→            .values()
 51→            .filter(|c| stage.is_none_or(|s| c.stage == s))
 52→            .filter(|c| {
 53→                search_lower.as_deref().is_none_or(|term| {
 54→                    c.name.to_lowercase().contains(term)
 55→                        || c.email
 56→                            .as_ref()
 57→                            .is_some_and(|e| e.expose_secret().to_lowercase().contains(term))
 58→                        || c.phone
 59→                            .as_ref()
 60→                            .is_some_and(|p| p.expose_secret().to_lowercase().contains(term))
 61→                })
 62→            })
 63→            .cloned()
 64→            .collect();
 65→        out.sort_by_key(|c| std::cmp::Reverse(c.updated_at));
 66→        let offset = offset as usize;
 67→        let limit = limit as usize;
 68→        Ok(out.into_iter().skip(offset).take(limit).collect())
 69→    }
 70→
 71→    async fn get(&self, id: &str) -> Result<Option<Contact>> {
 72→        let contacts = self.contacts.read().unwrap_or_else(|e| e.into_inner());
 73→        Ok(contacts.get(id).cloned())
 74→    }
 75→
 76→    async fn get_by_external(&self, source: &str, external_id: &str) -> Result<Option<Contact>> {
 77→        let contacts = self.contacts.read().unwrap_or_else(|e| e.into_inner());
 78→        Ok(contacts
 79→            .values()
 80→            .find(|c| {
 81→                c.source.as_deref() == Some(source) && c.external_id.as_deref() == Some(external_id)
 82→            })
 83→            .cloned())
 84→    }
 85→
 86→    async fn upsert(&self, contact: Contact) -> Result<()> {
 87→        let mut contacts = self.contacts.write().unwrap_or_else(|e| e.into_inner());
 88→        contacts.insert(contact.id.clone(), contact);
 89→        Ok(())
 90→    }
